// mm/src/pages/workflowPage.js
import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';

import WorkflowContainer from '../components/WorkflowContainer';
import UploadStep from '../steps/uploadStep';
import DesignStep from '../steps/designStep';
import PreviewStep from '../steps/previewStage';
import DetailsStep from '../steps/detailsStep';
import DownloadStep from '../steps/downloadStep';
import { useWorkflow } from '../store/workflowContext';

const WorkflowPage = () => {
  const { manuscriptFiles, design } = useWorkflow();

  // ----- STEP 1: Upload -----
  // You can go forward as soon as at least one file is uploaded
  const canProceedUpload = manuscriptFiles && manuscriptFiles.length > 0;

  // ----- STEP 2: Design -----
  // Require that analysis is complete and the user has typography, layout, and trim picks
  const canProceedDesign =
    !!design &&
    design.analyzed &&
    !!design.typography &&
    !!design.layout &&
    !!design.trim;

  return (
    <Routes>
      {/* Upload & Organize */}
      <Route
        path="start"
        element={
          <WorkflowContainer
            title="Upload & Organize"
            description="Upload your manuscript files and organize them for formatting"
            step={1}
            // ALWAYS show the Continue button on this step,
            // but disable it until a file is present
            hideNext={false}
            canProceed={canProceedUpload}
            // We don't want the save-progress modal on Upload
            disableSavePrompt={true}
          >
            <UploadStep />
          </WorkflowContainer>
        }
      />

      {/* Design */}
      <Route
        path="design"
        element={
          <WorkflowContainer
            title="Design Your Book"
            description="Customize typography, layout, and format with AI-powered recommendations"
            step={2}
            canProceed={canProceedDesign}
          >
            <DesignStep />
          </WorkflowContainer>
        }
      />

      {/* Preview */}
      <Route
        path="preview"
        element={
          <WorkflowContainer
            title="Preview"
            description="Check how pages will look with your chosen design"
            step={3}
            canProceed={true}
          >
            <PreviewStep />
          </WorkflowContainer>
        }
      />

      {/* Details */}
      <Route
        path="details"
        element={
          <WorkflowContainer
            title="Details"
            description="Add book metadata and publishing options"
            step={4}
            canProceed={true}
          >
            <DetailsStep />
          </WorkflowContainer>
        }
      />

      {/* Download */}
      <Route
        path="download"
        element={
          <WorkflowContainer
            title="Download"
            description="Download formatted files and upload packages"
            step={5}
            canProceed={true}
          >
            <DownloadStep />
          </WorkflowContainer>
        }
      />

      {/* /workflow should redirect to /workflow/start */}
      <Route index element={<Navigate to="start" replace />} />
    </Routes>
  );
};

export default WorkflowPage;
